def job_sequencing(jobs):
    jobs.sort(key=lambda x: x[2], reverse=True)

    max_deadline = 0
    if jobs:
        max_deadline = max(job[1] for job in jobs)

    scheduled_slots = [None] * (max_deadline + 1)

    total_profit = 0

    for job_id, deadline, profit in jobs:
        for i in range(deadline, 0, -1):
            if scheduled_slots[i] is None:
                scheduled_slots[i] = job_id
                total_profit += profit
                break

    final_sequence_by_time = [job_id for job_id in scheduled_slots if job_id is not None]

    return final_sequence_by_time, total_profit
